#include<bits/stdc++.h>
using namespace std;
const int maxn=105;
long long n,p,a[maxn],b[maxn],z[maxn];
bool cheek(long long x) {
	long long t=0;
	for(int i=1; i<=n; i++) {
		if(x>z[i]) {
			t+=a[i]*z[i]+b[i]*(x-z[i]);
		} else {
			t+=a[i]*x;
		}
	}
	return t>=p;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>p;
	for(int i=1; i<=n; i++) {
		cin>>z[i]>>a[i]>>b[i];
	}
	long long l=0,r=1e12+5;
	while(l<=r) {
		long long mid=l+r>>1;
		if(cheek(mid)) {
			r=mid-1;
		} else {
			l=mid+1;
		}
	}
	cout<<l;
	return 0;
}
